printf(
                            wp_kses(
                                __('It seems that your site is popular (great!) You may want to check <a href="%s">these recommendations</a> to make sure that its performance stays up to par.', 'wordpress-popular-posts'),
                                [
                                    'a' => [
                                        'href' => []
                                    ]
                                ]
                            ),
                            'https://github.com/cabrerahector/wordpress-popular-posts/wiki/7.-Performance'
                        )

printf(
                        wp_kses(
                            /* translators: third placeholder corresponds to the I18N version of the "Plain" permalink structure option */
                            __('It looks like your site is not using <a href="%s">Pretty Permalinks</a>. Please <a href="%s">select a permalink structure</a> other than <em>%s</em> so WP Popular Posts can do its job.', 'wordpress-popular-posts'),
                            [
                                'a' => [
                                    'href' => []
                                ],
                                'em' => []
                            ]
                        ),
                        'https://wordpress.org/documentation/article/customize-permalinks/#pretty-permalinks',
                        esc_url(admin_url('options-permalink.php')),
                        __('Plain')
                    )

array_filter($settings, function($key) {
            return str_starts_with($key, 'wpp_taxonomy_'); // str_starts_with() requires either WP 5.9+ or PHP 8+
        }, ARRAY_FILTER_USE_KEY)

array_filter($settings, function($key) {
                return str_starts_with($key, 'wpp_taxonomy_slug_'); // str_starts_with() requires either WP 5.9+ or PHP 8+
            }, ARRAY_FILTER_USE_KEY)

array_filter($settings, function($key) use ($allowed_keys) {
            return in_array($key, $allowed_keys);
        }, ARRAY_FILTER_USE_KEY)

array_filter($scripts, function($script) {
                return (false === strpos($script, 'wpp-js') && false === strpos($script, 'wpp.js') && false === strpos($script, 'wpp.min.js'));
            })

$wpdb->query(
                    $wpdb->prepare("ALTER TABLE %i ALTER COLUMN day DROP DEFAULT;", "{$prefix}data")
                )

$wpdb->query(
                    $wpdb->prepare("ALTER TABLE %i ALTER COLUMN last_viewed DROP DEFAULT;", "{$prefix}data")
                )

$wpdb->query(
                    $wpdb->prepare("ALTER TABLE %i CHANGE last_viewed view_datetime datetime NOT NULL, ADD KEY view_datetime (view_datetime);", "{$prefix}summary")
                )

$wpdb->query(
                    $wpdb->prepare("ALTER TABLE %i ALTER COLUMN view_date DROP DEFAULT;", "{$prefix}summary")
                )

$wpdb->query(
                    $wpdb->prepare("ALTER TABLE %i ALTER COLUMN view_datetime DROP DEFAULT;", "{$prefix}summary")
                )

